const req = $input.first().json;
const headers = req.headers || {};
const expected = $env.KONATIVE_INTAKE_TOKEN;
const supplied = String(headers.authorization || headers.Authorization || '').replace(/^Bearer\s+/i, '');
if (!expected || supplied !== expected) throw new Error('Unauthorized Konative intake');
const payload = req.body || req;
if (payload.source !== 'konative.com' || !payload.sanityDocumentId || !payload.schemaType) throw new Error('Invalid intake envelope');
const d = payload.data || {};
const email = String(d.email || d.workEmail || '').trim().toLowerCase();
if (!email) throw new Error('Email is required');
const fullName = String(d.name || d.fullName || d.contactName || '').trim();
const parts = fullName.split(/\s+/).filter(Boolean);
const firstName = String(d.firstName || parts.shift() || 'Website').trim();
const lastName = String(d.lastName || parts.join(' ') || 'Inquiry').trim();
const organization = String(d.organization || d.company || d.companyName || d.tribe || d.nation || email.split('@')[1] || 'Website inquiry').trim();
const requirement = String(d.requirement || d.message || d.projectDescription || d.notes || d.serviceNeeded || '').trim();
const audience = String(d.audience || d.lane || d.projectType || '').toLowerCase();
const lane = audience.includes('trib') ? 'TRIBAL' : audience.includes('gaming') || audience.includes('casino') ? 'GAMING' : audience.includes('data') || audience.includes('colo') ? 'DATA_CENTER' : audience.includes('travel') ? 'TRAVEL' : 'ENTERPRISE';
return [{json:{source:payload.source,schemaType:payload.schemaType,sanityDocumentId:payload.sanityDocumentId,submittedAt:payload.submittedAt || new Date().toISOString(),email,firstName,lastName,organization,phone:String(d.phone || '').trim(),requirement,lane,raw:d}}];

const i = $input.first().json;
const api = String($env.TWENTY_API_URL || 'https://api.twenty.com').replace(/\/$/, '');
const token = $env.TWENTY_API_KEY;
if (!token) throw new Error('TWENTY_API_KEY is not configured');
async function gql(query, variables = {}) {
  const res = await fetch(`${api}/graphql`, {method:'POST',headers:{'Content-Type':'application/json','Authorization':`Bearer ${token}`},body:JSON.stringify({query,variables})});
  const body = await res.json();
  if (!res.ok || body.errors?.length) throw new Error(body.errors?.map(e=>e.message).join('; ') || `Twenty HTTP ${res.status}`);
  return body.data;
}
let company = (await gql(`query($filter: CompanyFilterInput){companies(filter:$filter,first:1){edges{node{id name}}}}`,{filter:{name:{eq:i.organization}}})).companies?.edges?.[0]?.node;
if (!company) company = (await gql(`mutation($input: CompanyCreateInput!){createCompany(data:$input){id name}}`,{input:{name:i.organization}})).createCompany;
let person = (await gql(`query($filter: PersonFilterInput){people(filter:$filter,first:1){edges{node{id name{firstName lastName}}}}}`,{filter:{emails:{primaryEmail:{eq:i.email}}}})).people?.edges?.[0]?.node;
if (!person) person = (await gql(`mutation($input: PersonCreateInput!){createPerson(data:$input){id name{firstName lastName}}}`,{input:{name:{firstName:i.firstName,lastName:i.lastName},emails:{primaryEmail:i.email,additionalEmails:[]},phones:i.phone?{primaryPhoneNumber:i.phone,primaryPhoneCallingCode:'',primaryPhoneCountryCode:'US',additionalPhones:[]}:undefined,companyId:company.id}})).createPerson;
const oppName = `${i.organization} — ${i.schemaType} — ${i.sanityDocumentId}`;
let opportunity = (await gql(`query($filter: OpportunityFilterInput){opportunities(filter:$filter,first:1){edges{node{id name}}}}`,{filter:{name:{eq:oppName}}})).opportunities?.edges?.[0]?.node;
if (!opportunity) opportunity = (await gql(`mutation($input: OpportunityCreateInput!){createOpportunity(data:$input){id name}}`,{input:{name:oppName,stage:'NEW',lane:i.lane,signalSource:'website_inbound',companyId:company.id,notes:`Sanity: ${i.sanityDocumentId}\nSubmitted: ${i.submittedAt}\nRequirement: ${i.requirement || 'Not supplied'}`}})).createOpportunity;
let task = null;
try { task = (await gql(`mutation($input: TaskCreateInput!){createTask(data:$input){id title}}`,{input:{title:`Review Konative inquiry: ${i.organization}`,body:`Website intake ${i.sanityDocumentId}. ${i.requirement || ''}`.trim(),dueAt:new Date(Date.now()+86400000).toISOString(),status:'TODO'}})).createTask; } catch (error) { task = {id:null,warning:error.message}; }
return [{json:{ok:true,companyId:company.id,personId:person.id,opportunityId:opportunity.id,taskId:task?.id || null,taskWarning:task?.warning || null,sanityDocumentId:i.sanityDocumentId}}];
